    @PostMapping("/publish-batch")
    public ResponseEntity<Map<String, Object>> publishBatch(
            @RequestBody List<EventMessage> eventMessages,
            @RequestHeader(value = "X-Tracking-Id", required = false) String trackingId,
            @RequestHeader(value = "X-User-Id", required = false) String userId,
            @RequestHeader(value = "X-Batch-Id", required = false) String batchId) {

        String resolvedBatchId = batchId != null ? batchId : UUID.randomUUID().toString();
        List<Map<String, String>> results = new java.util.ArrayList<>();

        for (EventMessage eventMessage : eventMessages) {
            String topic = eventMessage.getTopic() != null ? eventMessage.getTopic() : DEFAULT_TOPIC;
            String key = eventMessage.getKey() != null ? eventMessage.getKey() : UUID.randomUUID().toString();
            String messageId = UUID.randomUUID().toString();

            ProducerRecord<String, String> record = new ProducerRecord<>(topic, key, eventMessage.getPayload());
            Headers recordHeaders = record.headers();

            recordHeaders.add("message-id", messageId.getBytes(StandardCharsets.UTF_8));
            recordHeaders.add("batch-id", resolvedBatchId.getBytes(StandardCharsets.UTF_8));
            recordHeaders.add("timestamp", String.valueOf(System.currentTimeMillis()).getBytes(StandardCharsets.UTF_8));

            addHeaderIfPresent(recordHeaders, "tracking-id", trackingId);
            addHeaderIfPresent(recordHeaders, "user-id", userId);

            if (eventMessage.getHeaders() != null) {
                eventMessage.getHeaders().forEach((k, v) ->
                        recordHeaders.add(k, v.getBytes(StandardCharsets.UTF_8)));
            }

            kafkaProducer.send(record, (metadata, exception) -> {
                if (exception != null) {
                    System.err.println("Batch message failed - id: " + messageId + ", error: " + exception.getMessage());
                }
            });

            Map<String, String> result = new HashMap<>();
            result.put("messageId", messageId);
            result.put("status", "QUEUED");
            results.add(result);
        }

        kafkaProducer.flush();

        Map<String, Object> response = new HashMap<>();
        response.put("batchId", resolvedBatchId);
        response.put("totalMessages", eventMessages.size());
        response.put("status", "ACCEPTED");
        response.put("messages", results);

        return ResponseEntity.accepted().body(response);
    }

    private void addHeaderIfPresent(Headers headers, String key, String value) {
        if (value != null && !value.isEmpty()) {
            headers.add(key, value.getBytes(StandardCharsets.UTF_8));
        }
    }

    @PreDestroy
    public void cleanup() {
        if (kafkaProducer != null) {
            kafkaProducer.flush();
            kafkaProducer.close();
        }
    }
